-- Initial schema for flash sale reservation system

CREATE EXTENSION IF NOT EXISTS "pgcrypto";

CREATE TABLE IF NOT EXISTS items (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name TEXT NOT NULL,
    total_quantity INT NOT NULL CHECK (total_quantity >= 0),
    reserved_quantity INT NOT NULL DEFAULT 0 CHECK (reserved_quantity >= 0),
    CONSTRAINT items_reserved_lte_total CHECK (reserved_quantity <= total_quantity)
);

CREATE TABLE IF NOT EXISTS reservations (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    item_id UUID NOT NULL REFERENCES items(id),
    user_id TEXT NOT NULL,
    quantity INT NOT NULL CHECK (quantity > 0),
    status TEXT NOT NULL CHECK (status IN ('active', 'released', 'expired')),
    expires_at TIMESTAMPTZ NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_reservations_user_status ON reservations(user_id, status);
CREATE INDEX IF NOT EXISTS idx_reservations_status_expires ON reservations(status, expires_at);

CREATE TABLE IF NOT EXISTS idempotency_keys (
    key TEXT PRIMARY KEY,
    request_hash TEXT NOT NULL,
    response_status INT NOT NULL,
    response_body JSONB NOT NULL,
    reservation_id UUID REFERENCES reservations(id),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

package main

import (
	"context"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/flash-reservation/backend/internal/api"
	"github.com/flash-reservation/backend/internal/clock"
	"github.com/flash-reservation/backend/internal/db"
	"github.com/flash-reservation/backend/internal/service"
)

func main() {
	ctx := context.Background()

	databaseURL := envOr("DATABASE_URL", "postgres://postgres:postgres@localhost:5432/reservations?sslmode=disable")
	port := envOr("PORT", "8080")
	ttlSeconds := 60
	expireInterval := 5 * time.Second

	pool, err := db.NewPool(ctx, databaseURL)
	if err != nil {
		log.Fatalf("database pool: %v", err)
	}
	defer pool.Close()

	if err := db.RunMigrations(ctx, pool, "migrations"); err != nil {
		log.Fatalf("migrations: %v", err)
	}
	if err := db.RunSeed(ctx, pool, "seeds/seed.sql"); err != nil {
		log.Fatalf("seed: %v", err)
	}

	sysClock := clock.System{}
	reservationSvc := service.NewReservationService(pool, sysClock, ttlSeconds)
	expirationSvc := service.NewExpirationService(pool, sysClock)

	expireCtx, cancelExpire := context.WithCancel(ctx)
	defer cancelExpire()
	go expirationSvc.Run(expireCtx, expireInterval)

	router := api.NewRouter(reservationSvc, "specs/001-inventory-reservation/contracts/openapi.yaml")

	srv := &http.Server{
		Addr:              ":" + port,
		Handler:           router,
		ReadHeaderTimeout: 5 * time.Second,
	}

	go func() {
		log.Printf("API listening on :%s", port)
		if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			log.Fatalf("server: %v", err)
		}
	}()

	stop := make(chan os.Signal, 1)
	signal.Notify(stop, syscall.SIGINT, syscall.SIGTERM)
	<-stop

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	cancelExpire()
	if err := srv.Shutdown(shutdownCtx); err != nil {
		log.Printf("shutdown: %v", err)
	}
}

func envOr(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

package clock

import "time"

type Clock interface {
	Now() time.Time
}

type System struct{}

func (System) Now() time.Time { return time.Now() }

type Fixed struct {
	T time.Time
}

func (f Fixed) Now() time.Time { return f.T }

package db

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/jackc/pgx/v5/pgxpool"
)

func NewPool(ctx context.Context, databaseURL string) (*pgxpool.Pool, error) {
	cfg, err := pgxpool.ParseConfig(databaseURL)
	if err != nil {
		return nil, fmt.Errorf("parse config: %w", err)
	}
	return pgxpool.NewWithConfig(ctx, cfg)
}

func RunMigrations(ctx context.Context, pool *pgxpool.Pool, dir string) error {
	entries, err := os.ReadDir(dir)
	if err != nil {
		return fmt.Errorf("read migrations dir: %w", err)
	}
	for _, e := range entries {
		if e.IsDir() || !strings.HasSuffix(e.Name(), ".sql") {
			continue
		}
		body, err := os.ReadFile(filepath.Join(dir, e.Name()))
		if err != nil {
			return fmt.Errorf("read migration %s: %w", e.Name(), err)
		}
		if _, err := pool.Exec(ctx, string(body)); err != nil {
			return fmt.Errorf("exec migration %s: %w", e.Name(), err)
		}
	}
	return nil
}

func RunSeed(ctx context.Context, pool *pgxpool.Pool, path string) error {
	if _, err := os.Stat(path); os.IsNotExist(err) {
		return nil
	}
	body, err := os.ReadFile(path)
	if err != nil {
		return fmt.Errorf("read seed: %w", err)
	}
	if _, err := pool.Exec(ctx, string(body)); err != nil {
		return fmt.Errorf("exec seed: %w", err)
	}
	return nil
}

package models

import (
	"time"

	"github.com/google/uuid"
)

type InventoryItem struct {
	ID               uuid.UUID `json:"id"`
	Name             string    `json:"name"`
	TotalQuantity    int       `json:"total_quantity"`
	ReservedQuantity int       `json:"reserved_quantity"`
	AvailableQuantity int      `json:"available_quantity"`
}

type Reservation struct {
	ID        uuid.UUID `json:"id"`
	ItemID    uuid.UUID `json:"item_id"`
	ItemName  string    `json:"item_name"`
	Quantity  int       `json:"quantity"`
	Status    string    `json:"status"`
	ExpiresAt time.Time `json:"expires_at"`
	CreatedAt time.Time `json:"created_at"`
}

type ReleaseResult struct {
	ID     uuid.UUID `json:"id"`
	Status string    `json:"status"`
	Noop   bool      `json:"noop"`
}

type CreateReservationRequest struct {
	ItemID   uuid.UUID `json:"item_id"`
	Quantity int       `json:"quantity"`
}

type APIError struct {
	Code    string `json:"code"`
	Message string `json:"message"`
}

type ErrorResponse struct {
	Error APIError `json:"error"`
}

const (
	StatusActive   = "active"
	StatusReleased = "released"
	StatusExpired  = "expired"
)

const (
	ErrInsufficientStock    = "INSUFFICIENT_STOCK"
	ErrIdempotencyConflict  = "IDEMPOTENCY_CONFLICT"
	ErrNotFound             = "NOT_FOUND"
	ErrForbidden            = "FORBIDDEN"
	ErrValidation           = "VALIDATION_ERROR"
	ErrMissingUserID        = "MISSING_USER_ID"
	ErrMissingIdempotencyKey = "MISSING_IDEMPOTENCY_KEY"
)

package service

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"time"

	"github.com/flash-reservation/backend/internal/clock"
	"github.com/flash-reservation/backend/internal/models"
	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
)

type ReservationService struct {
	pool       *pgxpool.Pool
	clock      clock.Clock
	ttlSeconds int
}

func NewReservationService(pool *pgxpool.Pool, c clock.Clock, ttlSeconds int) *ReservationService {
	return &ReservationService{pool: pool, clock: c, ttlSeconds: ttlSeconds}
}

func (s *ReservationService) ListInventory(ctx context.Context) ([]models.InventoryItem, error) {
	rows, err := s.pool.Query(ctx, `
		SELECT id, name, total_quantity, reserved_quantity,
		       total_quantity - reserved_quantity AS available_quantity
		FROM items
		ORDER BY name`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var items []models.InventoryItem
	for rows.Next() {
		var item models.InventoryItem
		if err := rows.Scan(&item.ID, &item.Name, &item.TotalQuantity, &item.ReservedQuantity, &item.AvailableQuantity); err != nil {
			return nil, err
		}
		items = append(items, item)
	}
	return items, rows.Err()
}

func (s *ReservationService) ListActiveReservations(ctx context.Context, userID string) ([]models.Reservation, error) {
	rows, err := s.pool.Query(ctx, `
		SELECT r.id, r.item_id, i.name, r.quantity, r.status, r.expires_at, r.created_at
		FROM reservations r
		JOIN items i ON i.id = r.item_id
		WHERE r.user_id = $1 AND r.status = 'active'
		ORDER BY r.created_at DESC`, userID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var list []models.Reservation
	for rows.Next() {
		var r models.Reservation
		if err := rows.Scan(&r.ID, &r.ItemID, &r.ItemName, &r.Quantity, &r.Status, &r.ExpiresAt, &r.CreatedAt); err != nil {
			return nil, err
		}
		list = append(list, r)
	}
	return list, rows.Err()
}

func hashRequest(itemID uuid.UUID, quantity int) string {
	payload := struct {
		ItemID   string `json:"item_id"`
		Quantity int    `json:"quantity"`
	}{ItemID: itemID.String(), Quantity: quantity}
	b, _ := json.Marshal(payload)
	sum := sha256.Sum256(b)
	return hex.EncodeToString(sum[:])
}

func (s *ReservationService) CreateReservation(ctx context.Context, userID, idempotencyKey string, req models.CreateReservationRequest) (models.Reservation, int, error) {
	if req.Quantity < 1 {
		return models.Reservation{}, 0, fmt.Errorf("%s: quantity must be at least 1", models.ErrValidation)
	}

	reqHash := hashRequest(req.ItemID, req.Quantity)
	tx, err := s.pool.Begin(ctx)
	if err != nil {
		return models.Reservation{}, 0, err
	}
	defer tx.Rollback(ctx)

	var existingStatus int
	var existingBody []byte
	err = tx.QueryRow(ctx, `
		SELECT response_status, response_body
		FROM idempotency_keys
		WHERE key = $1
		FOR UPDATE`, idempotencyKey).Scan(&existingStatus, &existingBody)
	if err == nil {
		var storedHash string
		_ = json.Unmarshal(existingBody, &struct {
			RequestHash string `json:"_request_hash"`
		}{})
		// Re-read hash from dedicated column via join pattern - store in response
		err = tx.QueryRow(ctx, `SELECT request_hash FROM idempotency_keys WHERE key = $1`, idempotencyKey).Scan(&storedHash)
		if err != nil {
			return models.Reservation{}, 0, err
		}
		if storedHash != reqHash {
			return models.Reservation{}, 0, fmt.Errorf("%s: idempotency key reused with different payload", models.ErrIdempotencyConflict)
		}
		var reservation models.Reservation
		if err := json.Unmarshal(existingBody, &reservation); err != nil {
			return models.Reservation{}, 0, err
		}
		if err := tx.Commit(ctx); err != nil {
			return models.Reservation{}, 0, err
		}
		status := existingStatus
		if status == 201 {
			return reservation, 200, nil
		}
		return reservation, status, nil
	}
	if !errors.Is(err, pgx.ErrNoRows) {
		return models.Reservation{}, 0, err
	}

	var itemName string
	var totalQty, reservedQty int
	err = tx.QueryRow(ctx, `
		SELECT name, total_quantity, reserved_quantity
		FROM items WHERE id = $1 FOR UPDATE`, req.ItemID).Scan(&itemName, &totalQty, &reservedQty)
	if errors.Is(err, pgx.ErrNoRows) {
		return models.Reservation{}, 0, fmt.Errorf("%s: item not found", models.ErrNotFound)
	}
	if err != nil {
		return models.Reservation{}, 0, err
	}

	tag, err := tx.Exec(ctx, `
		UPDATE items SET reserved_quantity = reserved_quantity + $1
		WHERE id = $2 AND total_quantity - reserved_quantity >= $1`, req.Quantity, req.ItemID)
	if err != nil {
		return models.Reservation{}, 0, err
	}
	if tag.RowsAffected() == 0 {
		return models.Reservation{}, 0, fmt.Errorf("%s: not enough stock available", models.ErrInsufficientStock)
	}

	now := s.clock.Now()
	expiresAt := now.Add(time.Duration(s.ttlSeconds) * time.Second)
	resID := uuid.New()

	var reservation models.Reservation
	err = tx.QueryRow(ctx, `
		INSERT INTO reservations (id, item_id, user_id, quantity, status, expires_at, created_at, updated_at)
		VALUES ($1, $2, $3, $4, 'active', $5, $6, $6)
		RETURNING id, item_id, quantity, status, expires_at, created_at`,
		resID, req.ItemID, userID, req.Quantity, expiresAt, now,
	).Scan(&reservation.ID, &reservation.ItemID, &reservation.Quantity, &reservation.Status, &reservation.ExpiresAt, &reservation.CreatedAt)
	if err != nil {
		return models.Reservation{}, 0, err
	}
	reservation.ItemName = itemName

	body, err := json.Marshal(reservation)
	if err != nil {
		return models.Reservation{}, 0, err
	}

	_, err = tx.Exec(ctx, `
		INSERT INTO idempotency_keys (key, request_hash, response_status, response_body, reservation_id)
		VALUES ($1, $2, 201, $3, $4)`,
		idempotencyKey, reqHash, body, reservation.ID)
	if err != nil {
		return models.Reservation{}, 0, err
	}

	if err := tx.Commit(ctx); err != nil {
		return models.Reservation{}, 0, err
	}
	return reservation, 201, nil
}

func (s *ReservationService) ReleaseReservation(ctx context.Context, userID string, reservationID uuid.UUID) (models.ReleaseResult, error) {
	tx, err := s.pool.Begin(ctx)
	if err != nil {
		return models.ReleaseResult{}, err
	}
	defer tx.Rollback(ctx)

	var ownerID, status string
	var itemID uuid.UUID
	var quantity int
	err = tx.QueryRow(ctx, `
		SELECT user_id, status, item_id, quantity
		FROM reservations WHERE id = $1 FOR UPDATE`, reservationID).Scan(&ownerID, &status, &itemID, &quantity)
	if errors.Is(err, pgx.ErrNoRows) {
		return models.ReleaseResult{}, fmt.Errorf("%s: reservation not found", models.ErrNotFound)
	}
	if err != nil {
		return models.ReleaseResult{}, err
	}
	if ownerID != userID {
		return models.ReleaseResult{}, fmt.Errorf("%s: not your reservation", models.ErrForbidden)
	}

	if status != models.StatusActive {
		if err := tx.Commit(ctx); err != nil {
			return models.ReleaseResult{}, err
		}
		return models.ReleaseResult{ID: reservationID, Status: status, Noop: true}, nil
	}

	tag, err := tx.Exec(ctx, `
		UPDATE reservations SET status = 'released', updated_at = $2
		WHERE id = $1 AND status = 'active'`, reservationID, s.clock.Now())
	if err != nil {
		return models.ReleaseResult{}, err
	}
	if tag.RowsAffected() == 0 {
		if err := tx.Commit(ctx); err != nil {
			return models.ReleaseResult{}, err
		}
		return models.ReleaseResult{ID: reservationID, Status: models.StatusReleased, Noop: true}, nil
	}

	_, err = tx.Exec(ctx, `
		UPDATE items SET reserved_quantity = reserved_quantity - $1
		WHERE id = $2`, quantity, itemID)
	if err != nil {
		return models.ReleaseResult{}, err
	}

	if err := tx.Commit(ctx); err != nil {
		return models.ReleaseResult{}, err
	}
	return models.ReleaseResult{ID: reservationID, Status: models.StatusReleased, Noop: false}, nil
}

// ExpirationService expires active reservations past TTL.
type ExpirationService struct {
	pool  *pgxpool.Pool
	clock clock.Clock
}

func NewExpirationService(pool *pgxpool.Pool, c clock.Clock) *ExpirationService {
	return &ExpirationService{pool: pool, clock: c}
}

func (s *ExpirationService) Run(ctx context.Context, interval time.Duration) {
	ticker := time.NewTicker(interval)
	defer ticker.Stop()
	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			_ = s.ExpireOnce(ctx)
		}
	}
}

func (s *ExpirationService) ExpireOnce(ctx context.Context) error {
	tx, err := s.pool.Begin(ctx)
	if err != nil {
		return err
	}
	defer tx.Rollback(ctx)

	rows, err := tx.Query(ctx, `
		UPDATE reservations SET status = 'expired', updated_at = $1
		WHERE status = 'active' AND expires_at <= $1
		RETURNING id, item_id, quantity`, s.clock.Now())
	if err != nil {
		return err
	}
	defer rows.Close()

	for rows.Next() {
		var id, itemID uuid.UUID
		var qty int
		if err := rows.Scan(&id, &itemID, &qty); err != nil {
			return err
		}
		if _, err := tx.Exec(ctx, `
			UPDATE items SET reserved_quantity = reserved_quantity - $1
			WHERE id = $2`, qty, itemID); err != nil {
			return err
		}
	}
	if err := rows.Err(); err != nil {
		return err
	}
	return tx.Commit(ctx)
}

// Test helpers used by integration tests
func (s *ReservationService) Pool() *pgxpool.Pool { return s.pool }

func (s *ReservationService) ResetItemStock(ctx context.Context, itemID uuid.UUID, total int) error {
	_, err := s.pool.Exec(ctx, `
		UPDATE items SET total_quantity = $2, reserved_quantity = 0 WHERE id = $1`, itemID, total)
	return err
}

func (s *ReservationService) GetItem(ctx context.Context, itemID uuid.UUID) (total, reserved int, err error) {
	err = s.pool.QueryRow(ctx, `
		SELECT total_quantity, reserved_quantity FROM items WHERE id = $1`, itemID).Scan(&total, &reserved)
	return
}

func (s *ReservationService) CreateTestItem(ctx context.Context, name string, total int) (uuid.UUID, error) {
	id := uuid.New()
	_, err := s.pool.Exec(ctx, `
		INSERT INTO items (id, name, total_quantity, reserved_quantity) VALUES ($1, $2, $3, 0)`, id, name, total)
	return id, err
}

func (s *ReservationService) CountActiveReservations(ctx context.Context, itemID uuid.UUID) (int, error) {
	var n int
	err := s.pool.QueryRow(ctx, `
		SELECT COUNT(*) FROM reservations WHERE item_id = $1 AND status = 'active'`, itemID).Scan(&n)
	return n, err
}

package api

import (
	"encoding/json"
	"errors"
	"net/http"
	"os"
	"strings"

	"github.com/flash-reservation/backend/internal/models"
	"github.com/flash-reservation/backend/internal/service"
	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	"github.com/google/uuid"
)

type Server struct {
	reservations *service.ReservationService
	openAPIPath  string
}

func NewRouter(svc *service.ReservationService, openAPIPath string) http.Handler {
	s := &Server{reservations: svc, openAPIPath: openAPIPath}
	r := chi.NewRouter()
	r.Use(middleware.RequestID)
	r.Use(middleware.RealIP)
	r.Use(middleware.Logger)
	r.Use(middleware.Recoverer)
	r.Use(corsMiddleware)

	r.Get("/health", func(w http.ResponseWriter, _ *http.Request) {
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte("ok"))
	})

	r.Get("/openapi.yaml", s.serveOpenAPI)

	r.Route("/api/v1", func(r chi.Router) {
		r.Get("/inventory", s.listInventory)
		r.Route("/reservations", func(r chi.Router) {
			r.Get("/", s.listReservations)
			r.Post("/", s.createReservation)
			r.Delete("/{id}", s.releaseReservation)
		})
	})

	return r
}

func corsMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Access-Control-Allow-Origin", "*")
		w.Header().Set("Access-Control-Allow-Methods", "GET, POST, DELETE, OPTIONS")
		w.Header().Set("Access-Control-Allow-Headers", "Content-Type, X-User-Id, Idempotency-Key")
		if r.Method == http.MethodOptions {
			w.WriteHeader(http.StatusNoContent)
			return
		}
		next.ServeHTTP(w, r)
	})
}

func (s *Server) serveOpenAPI(w http.ResponseWriter, r *http.Request) {
	data, err := os.ReadFile(s.openAPIPath)
	if err != nil {
		writeError(w, http.StatusNotFound, models.ErrNotFound, "OpenAPI spec not found")
		return
	}
	w.Header().Set("Content-Type", "application/yaml")
	w.WriteHeader(http.StatusOK)
	_, _ = w.Write(data)
}

func (s *Server) listInventory(w http.ResponseWriter, r *http.Request) {
	items, err := s.reservations.ListInventory(r.Context())
	if err != nil {
		writeError(w, http.StatusInternalServerError, "INTERNAL", err.Error())
		return
	}
	writeJSON(w, http.StatusOK, map[string]any{"items": items})
}

func (s *Server) listReservations(w http.ResponseWriter, r *http.Request) {
	userID := strings.TrimSpace(r.Header.Get("X-User-Id"))
	if userID == "" {
		writeError(w, http.StatusBadRequest, models.ErrMissingUserID, "X-User-Id header is required")
		return
	}
	list, err := s.reservations.ListActiveReservations(r.Context(), userID)
	if err != nil {
		writeError(w, http.StatusInternalServerError, "INTERNAL", err.Error())
		return
	}
	if list == nil {
		list = []models.Reservation{}
	}
	writeJSON(w, http.StatusOK, map[string]any{"reservations": list})
}

func (s *Server) createReservation(w http.ResponseWriter, r *http.Request) {
	userID := strings.TrimSpace(r.Header.Get("X-User-Id"))
	if userID == "" {
		writeError(w, http.StatusBadRequest, models.ErrMissingUserID, "X-User-Id header is required")
		return
	}
	idempotencyKey := strings.TrimSpace(r.Header.Get("Idempotency-Key"))
	if idempotencyKey == "" {
		writeError(w, http.StatusBadRequest, models.ErrMissingIdempotencyKey, "Idempotency-Key header is required")
		return
	}

	var req models.CreateReservationRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeError(w, http.StatusBadRequest, models.ErrValidation, "invalid JSON body")
		return
	}

	reservation, status, err := s.reservations.CreateReservation(r.Context(), userID, idempotencyKey, req)
	if err != nil {
		mapServiceError(w, err)
		return
	}
	writeJSON(w, status, reservation)
}

func (s *Server) releaseReservation(w http.ResponseWriter, r *http.Request) {
	userID := strings.TrimSpace(r.Header.Get("X-User-Id"))
	if userID == "" {
		writeError(w, http.StatusBadRequest, models.ErrMissingUserID, "X-User-Id header is required")
		return
	}
	idStr := chi.URLParam(r, "id")
	resID, err := uuid.Parse(idStr)
	if err != nil {
		writeError(w, http.StatusBadRequest, models.ErrValidation, "invalid reservation id")
		return
	}

	result, err := s.reservations.ReleaseReservation(r.Context(), userID, resID)
	if err != nil {
		mapServiceError(w, err)
		return
	}
	writeJSON(w, http.StatusOK, result)
}

func mapServiceError(w http.ResponseWriter, err error) {
	msg := err.Error()
	switch {
	case strings.Contains(msg, models.ErrInsufficientStock):
		writeError(w, http.StatusConflict, models.ErrInsufficientStock, "Not enough stock available for this reservation")
	case strings.Contains(msg, models.ErrIdempotencyConflict):
		writeError(w, http.StatusConflict, models.ErrIdempotencyConflict, "Idempotency key was already used with a different request payload")
	case strings.Contains(msg, models.ErrNotFound):
		writeError(w, http.StatusNotFound, models.ErrNotFound, strings.TrimPrefix(msg, models.ErrNotFound+": "))
	case strings.Contains(msg, models.ErrForbidden):
		writeError(w, http.StatusForbidden, models.ErrForbidden, strings.TrimPrefix(msg, models.ErrForbidden+": "))
	case strings.Contains(msg, models.ErrValidation):
